mapper.select:
SELECT
/* 일일 생산 LOT */ ( SELECT COUNT(*) FROM lot l INNER JOIN work w ON l.lot_work = w.work_id WHERE TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) AND l.lot_status != 0 ) AS "todayProdLotCnt",
/* 작업 완료 LOT */ ( SELECT COUNT(*) FROM lot l INNER JOIN work w ON l.lot_work = w.work_id WHERE TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) AND w.work_status = 30 AND l.lot_status != 0 ) AS "todayDoneLotCnt",
/* 일일 검사 LOT */ ( SELECT COUNT(DISTINCT q.qc_lot) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayQcLotCnt",
/* 일일 불량률 */ ( SELECT ROUND( NVL( SUM(q.qc_qty - q.qc_pass_qty), 0 ) / NULLIF( SUM(q.qc_qty), 0 ) * 100, 2 ) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayFailRate"
FROM dual
